class AppBindings extends Bindings {
  @override
  void dependencies() {
    Get.put(AuthService());
    Get.lazyPut<StorageService>(() => StorageService());
  }
}

// In main.dart
GetMaterialApp(
  initialBinding: AppBindings(),
