import 'package:flutter/material.dart';
import 'package:get/get.dart';

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return GetMaterialApp(
      title: 'GetX Bindings Demo',
      initialRoute: '/',
      getPages: [
        GetPage(
          name: '/',
          page: () => HomePage(),
          binding: HomeBinding(),
        ),
        GetPage(
          name: '/details',
          page: () => DetailsPage(),
          binding: DetailsBinding(),
        ),
      ],
    );
  }
}

// Controllers
class HomeController extends GetxController {
  var count = 0.obs;
  void increment() => count++;

  @override
  void onInit() {
    super.onInit();
    print('HomeController created');
  }

  @override
  void onClose() {
    print('HomeController disposed');
    super.onClose();
  }
}

class DetailsController extends GetxController {
  final String message;
  DetailsController(this.message);

  @override
  void onInit() {
    super.onInit();
    print('DetailsController created with message: $message');
  }

  @override
  void onClose() {
    print('DetailsController disposed');
    super.onClose();
  }
}

// Bindings
class HomeBinding extends Bindings {
  @override
  void dependencies() {
    Get.lazyPut(() => HomeController());
  }
}

class DetailsBinding extends Bindings {
  @override
  void dependencies() {
    Get.lazyPut(() => DetailsController('Hello from binding!'));
  }
}

// Views
class HomePage extends GetView<HomeController> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Home')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Obx(() => Text('Count: ${controller.count}', style: TextStyle(fontSize: 24))),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: controller.increment,
              child: Text('Increment'),
            ),
            ElevatedButton(
              onPressed: () => Get.toNamed('/details'),
              child: Text('Go to Details'),
            ),
          ],
        ),
      ),
    );
  }
}

class DetailsPage extends GetView<DetailsController> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Details')),
      body: Center(
        child: Text('Message: ${controller.message}'),
      ),
    );
  }
}
